import React, { useState, useEffect } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";
import TicketVenta from "../components/TicketVenta";

export default function Ventas() {
  const [productos, setProductos] = useState([]);
  const [clientes, setClientes] = useState([]);
  const [busquedaProducto, setBusquedaProducto] = useState("");
  const [productoSeleccionado, setProductoSeleccionado] = useState(null);
  const [clienteNombre, setClienteNombre] = useState("");
  const [clienteApellido, setClienteApellido] = useState("");
  const [clienteTelefono, setClienteTelefono] = useState("");
  const [cantidad, setCantidad] = useState(1);
  const [mensaje, setMensaje] = useState("");
  const [ticket, setTicket] = useState(null);
  const [carrito, setCarrito] = useState([]);

  useEffect(() => {
    obtenerProductos();
    obtenerClientes();
  }, []);

  const obtenerProductos = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/productos");
      setProductos(res.data);
    } catch (err) {
      console.error("Error al obtener productos:", err);
    }
  };

  const obtenerClientes = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/clientes");
      setClientes(res.data);
    } catch (err) {
      console.error("Error al obtener clientes:", err);
    }
  };

  const buscarProducto = (nombre) => {
    setBusquedaProducto(nombre);
    const producto = productos.find(
      (p) => (p.nombre || p.Nombre || "").toLowerCase() === nombre.toLowerCase()
    );
    setProductoSeleccionado(producto || null);
    setMensaje("");
  };

  const agregarAlCarrito = () => {
    if (!productoSeleccionado) return;

    const stock = Number(productoSeleccionado.stock || productoSeleccionado.Stock);
    if (stock < cantidad) {
      setMensaje("❌ Stock insuficiente.");
      return;
    }

    const existente = carrito.find(
      (p) => p.ProductID === (productoSeleccionado.ProductoID || productoSeleccionado.id)
    );

    if (existente) {
      const actualizado = carrito.map((p) =>
        p.ProductID === existente.ProductID
          ? { ...p, Cantidad: p.Cantidad + cantidad }
          : p
      );
      setCarrito(actualizado);
    } else {
      setCarrito([
        ...carrito,
        {
          ProductID: productoSeleccionado.ProductoID || productoSeleccionado.id,
          Nombre: productoSeleccionado.Nombre || productoSeleccionado.nombre,
          Cantidad: cantidad,
          PrecioUnitario: Number(productoSeleccionado.Precio || productoSeleccionado.precio),
        },
      ]);
    }

    setProductoSeleccionado(null);
    setBusquedaProducto("");
    setCantidad(1);
  };

  const calcularSubtotal = () => {
    return carrito.reduce((acc, p) => acc + p.Cantidad * p.PrecioUnitario, 0);
  };

  const realizarVenta = async () => {
    if (!clienteNombre.trim() || !clienteApellido.trim()) {
      setMensaje("⚠️ Ingresa nombre y apellido del cliente.");
      return;
    }

    if (carrito.length === 0) {
      setMensaje("⚠️ Agrega al menos un producto al carrito.");
      return;
    }

    try {
      let cliente = clientes.find(
        (c) =>
          (c.Nombre || c.nombre || "").toLowerCase() === clienteNombre.toLowerCase() &&
          (c.Apellido || c.apellido || "").toLowerCase() === clienteApellido.toLowerCase()
      );

      // Crear cliente automáticamente si no existe
      if (!cliente) {
        const resCliente = await axios.post("http://localhost:5000/api/clientes", {
          Nombre: clienteNombre,
          Apellido: clienteApellido,
          Telefono: clienteTelefono || "",
        });

        cliente = resCliente.data;
        if (!cliente.ClienteID && !cliente.id) {
          throw new Error("❌ No se recibió el ID del cliente creado.");
        }
        setClientes([...clientes, cliente]);
        setMensaje(`✅ Cliente "${clienteNombre} ${clienteApellido}" agregado.`);
      }

      // Preparar productos con la estructura que espera el backend
      const productosEnviar = carrito.map((p) => ({
        ProductoID: p.ProductID,
        Cantidad: p.Cantidad,
        PrecioUnitario: p.PrecioUnitario,
      }));

      // Registrar venta
      const res = await axios.post("http://localhost:5000/api/ventas", {
        ClienteID: cliente.ClienteID || cliente.id,
        productos: productosEnviar,
        EmisorNombre: "Mi Negocio",
      });

      // Preparar ticket con nombre completo
      setTicket({ ...res.data, NombreCliente: `${clienteNombre} ${clienteApellido}` });

      setMensaje("✅ Venta realizada correctamente.");
      setCarrito([]);
      setClienteNombre("");
      setClienteApellido("");
      setClienteTelefono("");
      obtenerProductos();
    } catch (err) {
      console.error("❌ Error al procesar la venta:", err);
      if (err.response && err.response.data && err.response.data.msg) {
        setMensaje(`❌ Error: ${err.response.data.msg}`);
      } else {
        setMensaje("❌ Error al procesar la venta.");
      }
    }
  };

  return (
    <div className="container mt-5">
      <div className="row">
        {/* Formulario productos y cliente */}
        <div className="col-md-6">
          <div className="card shadow p-4 mb-4">
            <h5 className="fw-bold mb-3">Agregar Productos</h5>

            <div className="mb-3">
              <label className="form-label">Producto</label>
              <input
                type="text"
                className="form-control"
                placeholder="Buscar producto..."
                value={busquedaProducto}
                onChange={(e) => buscarProducto(e.target.value)}
                list="listaProductos"
              />
              <datalist id="listaProductos">
                {productos.map((p) => (
                  <option key={p.ProductoID || p.id} value={p.Nombre || p.nombre} />
                ))}
              </datalist>
            </div>

            {productoSeleccionado && (
              <div className="mb-3">
                <p
                  className={`mb-1 ${
                    Number(productoSeleccionado.stock || productoSeleccionado.Stock) > 0
                      ? "text-success"
                      : "text-danger"
                  }`}
                >
                  {Number(productoSeleccionado.stock || productoSeleccionado.Stock) > 0
                    ? `✅ En stock: ${productoSeleccionado.stock || productoSeleccionado.Stock}`
                    : "❌ Agotado"}
                </p>
                <div className="d-flex gap-2">
                  <input
                    type="number"
                    className="form-control"
                    min="1"
                    value={cantidad}
                    onChange={(e) => setCantidad(Number(e.target.value))}
                  />
                  <button className="btn btn-primary" onClick={agregarAlCarrito}>
                    ➕ Agregar
                  </button>
                </div>
              </div>
            )}

            <h5 className="fw-bold mt-4 mb-2">Cliente</h5>
            <div className="mb-2">
              <input
                type="text"
                className="form-control mb-2"
                placeholder="Nombre"
                value={clienteNombre}
                onChange={(e) => setClienteNombre(e.target.value)}
              />
              <input
                type="text"
                className="form-control mb-2"
                placeholder="Apellido"
                value={clienteApellido}
                onChange={(e) => setClienteApellido(e.target.value)}
              />
              <input
                type="text"
                className="form-control mb-2"
                placeholder="Teléfono"
                value={clienteTelefono}
                onChange={(e) => setClienteTelefono(e.target.value)}
              />
            </div>

            {mensaje && <div className="alert alert-info mt-2">{mensaje}</div>}
          </div>
        </div>

        {/* Carrito */}
        <div className="col-md-6">
          <div className="card shadow p-4 mb-4">
            <h5 className="fw-bold mb-3">Carrito</h5>
            {carrito.length === 0 ? (
              <p>🛒 No hay productos agregados.</p>
            ) : (
              <table className="table table-sm">
                <thead>
                  <tr>
                    <th>Producto</th>
                    <th>Cant.</th>
                    <th>Subtot.</th>
                  </tr>
                </thead>
                <tbody>
                  {carrito.map((p, idx) => (
                    <tr key={idx}>
                      <td>{p.Nombre}</td>
                      <td>{p.Cantidad}</td>
                      <td>{(p.Cantidad * p.PrecioUnitario).toFixed(2)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}

            <div className="mt-3">
              <p className="d-flex justify-content-between">
                <span>Subtotal:</span>
                <span>{calcularSubtotal().toFixed(2)}</span>
              </p>
              <p className="d-flex justify-content-between">
                <span>IVA (13%):</span>
                <span>{(calcularSubtotal() * 0.13).toFixed(2)}</span>
              </p>
              <p className="d-flex justify-content-between fw-bold">
                <span>Total:</span>
                <span>{(calcularSubtotal() * 1.12).toFixed(2)}</span>
              </p>

              <button
                className="btn btn-success w-100 mt-3"
                onClick={realizarVenta}
                disabled={carrito.length === 0 || !clienteNombre || !clienteApellido}
              >
                💰 Realizar Venta
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Ticket */}
      <TicketVenta ticket={ticket} setTicket={setTicket} />
    </div>
  );
}
